using System;
using System.Collections.Generic;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

public static class Downloader
{
    public static async Task<string[]> DownloadAllAsync(
        IEnumerable<Uri> uris,
        Func<Uri, CancellationToken, Task<string>> fetch,
        CancellationToken cancellationToken)
    {
        if (uris == null) throw new ArgumentNullException(nameof(uris));
        if (fetch == null) throw new ArgumentNullException(nameof(fetch));

        cancellationToken.ThrowIfCancellationRequested();

        var tasks = uris.Select(uri => fetch(uri, cancellationToken)).ToArray();

        var whenAllTask = Task.WhenAll(tasks);

        var cancellationTcs = new TaskCompletionSource<bool>(TaskCreationOptions.RunContinuationsAsynchronously);
        using (cancellationToken.Register(() => cancellationTcs.TrySetCanceled(cancellationToken)))
        {
            var completed = await Task.WhenAny(whenAllTask, cancellationTcs.Task).ConfigureAwait(false);

            if (completed == cancellationTcs.Task)
            {
                // Await to throw the OperationCanceledException with correct token
                await cancellationTcs.Task.ConfigureAwait(false);
            }

            // If whenAllTask completed first (successfully or faulted), await it to propagate results/exceptions.
            return await whenAllTask.ConfigureAwait(false);
        }
    }
}

using System;
using System.Threading.Channels;
using System.Threading.Tasks;

public static class Pipeline
{
    public static async Task<long> ProduceConsumeSumAsync(int count)
    {
        if (count <= 0)
        {
            return 0L;
        }

        var channel = Channel.CreateBounded<int>(new BoundedChannelOptions(Math.Min(count, 100))
        {
            SingleReader = true,
            SingleWriter = true,
            FullMode = BoundedChannelFullMode.Wait
        });

        var producerTask = Task.Run(async () =>
        {
            try
            {
                for (int i = 0; i < count; i++)
                {
                    await channel.Writer.WriteAsync(i).ConfigureAwait(false);
                }
            }
            finally
            {
                channel.Writer.Complete();
            }
        });

        long sum = 0;
        await foreach (var value in channel.Reader.ReadAllAsync().ConfigureAwait(false))
        {
            sum += value;
        }

        await producerTask.ConfigureAwait(false);

        return sum;
    }
}

