public sealed class Lookup
{
    private readonly Dictionary<string, string> _map = new();

    public void Add(string key, string value)
    {
        _map[key] = value;
    }

    public bool TryGet(string key, out string? value)
    {
        if (_map.TryGetValue(key, out var found))
        {
            value = found;
            return true;
        }

        value = null;
        return false;
    }
}

