using System;

public static class TextScan
{
    public static int CountWords(ReadOnlySpan<char> text)
    {
        int count = 0;
        bool inWord = false;

        for (int i = 0; i < text.Length; i++)
        {
            if (char.IsWhiteSpace(text[i]))
            {
                inWord = false;
            }
            else
            {
                if (!inWord)
                {
                    count++;
                    inWord = true;
                }
            }
        }

        return count;
    }
}

using System;

public static class SpanParser
{
    public static int SumCsvInts(ReadOnlySpan<char> csv)
    {
        int sum = 0;
        ReadOnlySpan<char> remaining = csv;

        while (true)
        {
            int commaIndex = remaining.IndexOf(',');
            ReadOnlySpan<char> token;

            if (commaIndex >= 0)
            {
                token = remaining.Slice(0, commaIndex);
                remaining = remaining.Slice(commaIndex + 1);
            }
            else
            {
                token = remaining;
            }

            ReadOnlySpan<char> trimmed = token.Trim();

            if (!trimmed.IsEmpty)
            {
                sum += int.Parse(trimmed);
            }

            if (commaIndex < 0)
            {
                break;
            }
        }

        return sum;
    }
}
